import{_ as t,o,c as n,h as r}from"./chunks/framework.3WqHSPpF.js";const g=JSON.parse('{"title":"Contributing to Cobalt","description":"","frontmatter":{},"headers":[],"relativePath":"contributing/index.md","filePath":"contributing/index.md"}'),i={name:"contributing/index.md"};function a(s,e,l,d,u,c){return o(),n("div",null,[...e[0]||(e[0]=[r('<h1 id="contributing-to-cobalt" tabindex="-1">Contributing to Cobalt <a class="header-anchor" href="#contributing-to-cobalt" aria-label="Permalink to &quot;Contributing to Cobalt&quot;">​</a></h1><p>Thank you for your interest in contributing to the Cobalt Design System. Whether you&#39;re fixing a bug, proposing a new component, improving documentation, or sharing feedback, your contributions help make Cobalt better for everyone.</p><h2 id="ways-to-contribute" tabindex="-1">Ways to Contribute <a class="header-anchor" href="#ways-to-contribute" aria-label="Permalink to &quot;Ways to Contribute&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Contribution Type</th><th>Description</th><th>Getting Started</th></tr></thead><tbody><tr><td>Bug Reports</td><td>Found something broken? Let us know.</td><td><a href="./how-to-contribute.html">How to Contribute</a></td></tr><tr><td>Feature Requests</td><td>Have an idea for a new feature or enhancement?</td><td><a href="./how-to-contribute.html">How to Contribute</a></td></tr><tr><td>New Components</td><td>Propose and build a new component for the library.</td><td><a href="./component-proposal.html">Component Proposal</a></td></tr><tr><td>Code Contributions</td><td>Fix bugs, improve performance, or add features.</td><td><a href="./development-setup.html">Development Setup</a></td></tr><tr><td>Design Contributions</td><td>Propose design updates or new patterns in Figma.</td><td><a href="./design-contribution.html">Design Contribution</a></td></tr><tr><td>Documentation</td><td>Improve guides, examples, or API references.</td><td><a href="./development-setup.html">Development Setup</a></td></tr></tbody></table><h2 id="before-you-start" tabindex="-1">Before You Start <a class="header-anchor" href="#before-you-start" aria-label="Permalink to &quot;Before You Start&quot;">​</a></h2><ol><li><strong>Read the guidelines.</strong> Familiarize yourself with our <a href="./coding-standards.html">Coding Standards</a> and <a href="./versioning.html">Versioning &amp; Release Policy</a>.</li><li><strong>Check existing issues.</strong> Someone may already be working on what you have in mind. Search open issues and pull requests before starting new work.</li><li><strong>Start small.</strong> If this is your first contribution, look for issues labeled <code>good first issue</code> or <code>help wanted</code>.</li></ol><h2 id="quick-links" tabindex="-1">Quick Links <a class="header-anchor" href="#quick-links" aria-label="Permalink to &quot;Quick Links&quot;">​</a></h2><ul><li><a href="./how-to-contribute.html">How to Contribute</a> — Reporting bugs, requesting features, and submitting pull requests</li><li><a href="./component-proposal.html">Component Proposal Process</a> — The RFC workflow for proposing new components</li><li><a href="./development-setup.html">Development Setup</a> — Getting your local environment ready</li><li><a href="./coding-standards.html">Coding Standards</a> — TypeScript, Lit, CSS, and testing conventions</li><li><a href="./design-contribution.html">Design Contribution Guidelines</a> — Working with the Figma library and design reviews</li><li><a href="./versioning.html">Versioning &amp; Release Policy</a> — Semver, changesets, and release cadence</li></ul><h2 id="contribution-workflow-at-a-glance" tabindex="-1">Contribution Workflow at a Glance <a class="header-anchor" href="#contribution-workflow-at-a-glance" aria-label="Permalink to &quot;Contribution Workflow at a Glance&quot;">​</a></h2><p>The general process for contributing code or design changes follows these stages:</p><ol><li><strong>Identify the work</strong> — Find an existing issue or create one describing the change</li><li><strong>Discuss</strong> — For non-trivial changes, get alignment in the relevant Slack channel or GitHub Discussion before starting</li><li><strong>Set up your environment</strong> — Follow the <a href="./development-setup.html">Development Setup</a> guide</li><li><strong>Implement</strong> — Make your changes on a feature branch, following the <a href="./coding-standards.html">Coding Standards</a></li><li><strong>Add a changeset</strong> — Run <code>pnpm changeset</code> so your change is included in the next release</li><li><strong>Submit a pull request</strong> — Open a PR against <code>main</code> and fill out the template</li><li><strong>Review and iterate</strong> — Address feedback from reviewers until the PR is approved</li><li><strong>Merge</strong> — A core maintainer merges the PR once all checks pass</li></ol><h2 id="code-of-conduct" tabindex="-1">Code of Conduct <a class="header-anchor" href="#code-of-conduct" aria-label="Permalink to &quot;Code of Conduct&quot;">​</a></h2><p>All contributors are expected to follow our Code of Conduct. We are committed to providing a welcoming and inclusive experience for everyone. Please be respectful, constructive, and professional in all interactions.</p><h2 id="getting-help" tabindex="-1">Getting Help <a class="header-anchor" href="#getting-help" aria-label="Permalink to &quot;Getting Help&quot;">​</a></h2><p>If you&#39;re unsure where to start or have questions about the contribution process, reach out through any of these channels:</p><ul><li><strong>Slack:</strong> <code>#cobalt-contributors</code> in the internal workspace</li><li><strong>GitHub Discussions:</strong> Use the Q&amp;A category for questions</li><li><strong>Office Hours:</strong> The Cobalt team holds weekly office hours every Thursday at 2 PM ET</li></ul><blockquote><p><strong>Tip:</strong> Don&#39;t be afraid to ask questions. The team is happy to help you find the right area to contribute and guide you through the process.</p></blockquote><h2 id="recognition" tabindex="-1">Recognition <a class="header-anchor" href="#recognition" aria-label="Permalink to &quot;Recognition&quot;">​</a></h2><p>We value every contribution. All contributors are acknowledged in our release notes, and significant contributions are highlighted in our quarterly design system newsletter.</p>',19)])])}const p=t(i,[["render",a]]);export{g as __pageData,p as default};
